  8→} from "@chat-exporter/shared";
  9→import { ClipboardCopy } from "lucide-react";
 10→import React, {
 11→  memo,
 12→  useCallback,
 13→  useEffect,
 14→  useMemo,
 15→  useRef,
 16→  useState,
 17→} from "react";
 18→import { ErrorBoundary } from "@/components/error-boundary";
 19→import { BlockErrorFallback } from "@/components/format-workspace/block-error-fallback";
 20→import { BlockToolbar } from "@/components/format-workspace/block-toolbar";
 21→import { EditableBlock } from "@/components/format-workspace/editable-block";
 22→import { getRoleLabel } from "@/components/format-workspace/labels";
 23→import { MessageDeleteMenu } from "@/components/format-workspace/message-delete-menu";
 24→import {
 25→  blockToPlainText,
 26→  collectInserts,
 27→  getBlocksMatchingRule,
 28→  getReaderBlockClassName,
 29→  getReaderBlockStyle,
 30→  renderReaderBlock,
 31→} from "@/components/format-workspace/rule-engine";
 32→import type {
 33→  AdjustmentSelection,
 34→  ViewportAnchor,
 35→} from "@/components/format-workspace/types";
 36→import { cn } from "@/lib/utils";
 37→
 38→import {
 39→  SELECTION_DEBOUNCE_MS,
 40→  TEXT_PREVIEW_LIMIT,
 41→  TEXT_TRUNCATION_LIMIT,
 42→} from "./constants";
 43→
 44→/** Thin wrapper so that errors thrown by renderReaderBlock are caught by ErrorBoundary. */
 45→function BlockRenderer({
 46→  block,
 47→  effects,
 48→}: {
 49→  block: Block;
 50→  effects: RuleEffect[];
 51→}) {
 52→  return <>{renderReaderBlock(block, effects)}</>;
 53→}
 54→
 55→type ReaderViewProps = {
 56→  activeRules: FormatRule[];
 57→  adjustModeEnabled: boolean;
 58→  conversation: Conversation | undefined;
 59→  deletedMessageIds?: Set<string>;
 60→  editMode?: boolean;
 61→  effectsMap: Map<string, RuleEffect[]>;
 62→  highlightedRuleId: string | null;
 63→  onBlocksChange?: (messageId: string, blocks: Block[]) => void;
 64→  onCopyMessage?: (messageId: string) => void;
 65→  onDeleteMessage?: (messageId: string) => void;
 66→  onDeleteRound?: (messageId: string) => void;
 67→  onRestoreMessage?: (messageId: string) => Promise<{ restored: boolean }>;
 68→  onSelectBlock: (
 69→    selection: AdjustmentSelection,
 70→    anchor: ViewportAnchor,
 71→  ) => void;
 72→  selectedBlock: AdjustmentSelection | null;
 73→  showDeleted?: boolean;
 74→};
 75→
 76→function truncateSelectionText(value: string) {
 77→  return value.length > TEXT_TRUNCATION_LIMIT
 78→    ? `${value.slice(0, TEXT_PREVIEW_LIMIT).trimEnd()}...`
 79→    : value;
 80→}
 81→
 82→function toViewportAnchor(rect: DOMRect): ViewportAnchor {
 83→  return {
 84→    bottom: rect.bottom,
 85→    height: rect.height,
 86→    left: rect.left,
 87→    top: rect.top,
 88→    width: rect.width,
 89→  };
 90→}
 91→
 92→type ReaderMessageProps = {
 93→  adjustModeEnabled: boolean;
 94→  editMode?: boolean;
 95→  effectsMap: Map<string, RuleEffect[]>;
 96→  highlightedBlocks: Set<string>;
 97→  isDeleted?: boolean;
 98→  message: Message;
 99→  messageIndex: number;
100→  onBlockChange?: (
101→    messageId: string,
102→    blockIndex: number,
103→    newBlock: Block,
104→  ) => void;
105→  onBlocksChange?: (messageId: string, blocks: Block[]) => void;
106→  onCopyMessage?: () => void;
107→  onDeleteMessage?: () => void;
108→  onDeleteRound?: () => void;
109→  onRestore?: () => void;
110→  onSelectBlock: ReaderViewProps["onSelectBlock"];
111→  selectedBlock: AdjustmentSelection | null;
112→};
113→
114→const ReaderMessage = memo(function ReaderMessage({
115→  adjustModeEnabled,
116→  editMode,
117→  effectsMap,
118→  highlightedBlocks,
119→  isDeleted,
120→  message,
121→  messageIndex,
122→  onBlockChange,
123→  onBlocksChange,
124→  onCopyMessage,
125→  onDeleteMessage,
126→  onDeleteRound,
127→  onRestore,
128→  onSelectBlock,
129→  selectedBlock,
130→}: ReaderMessageProps) {
131→  const lastSelectionInteractionAt = useRef(0);
132→  const [hoveredBlockIndex, setHoveredBlockIndex] = useState<number | null>(
133→    null,
134→  );
135→  const hoverLeaveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
136→  const toolbarMenuOpen = useRef(false);
137→  const blocksRef = useRef(message.blocks);
138→  blocksRef.current = message.blocks;
139→  const handleToolbarMenuOpenChange = useCallback((open: boolean) => {
140→    toolbarMenuOpen.current = open;
141→  }, []);
142→
143→  const handleBlockMouseEnter = useCallback(
144→    (blockIndex: number) => {
145→      if (!editMode) return;
146→      if (hoverLeaveTimer.current) {
147→        clearTimeout(hoverLeaveTimer.current);
148→        hoverLeaveTimer.current = null;
149→      }
150→      setHoveredBlockIndex(blockIndex);
151→    },
152→    [editMode],
153→  );
154→
155→  const handleBlockMouseLeave = useCallback(() => {
156→    if (!editMode) return;
157→    if (toolbarMenuOpen.current) return;
158→    hoverLeaveTimer.current = setTimeout(() => {
159→      setHoveredBlockIndex(null);
160→      hoverLeaveTimer.current = null;
161→    }, 150);
162→  }, [editMode]);
163→
164→  const handleDeleteBlock = useCallback(
165→    (blockIndex: number) => {
166→      if (!onBlocksChange) return;
167→      const updatedBlocks = [...blocksRef.current];
168→      updatedBlocks.splice(blockIndex, 1);
169→      onBlocksChange(message.id, updatedBlocks);
170→    },
171→    [message.id, onBlocksChange],
172→  );
173→
174→  const handleDuplicateBlock = useCallback(
175→    (blockIndex: number) => {
176→      if (!onBlocksChange) return;
177→      const updatedBlocks = [...blocksRef.current];
178→      const original = updatedBlocks[blockIndex];
179→      if (!original) return;
180→      const copy = { ...original, id: generateBlockId() } as Block;
181→      updatedBlocks.splice(blockIndex + 1, 0, copy);
182→      onBlocksChange(message.id, updatedBlocks);
183→    },
184→    [message.id, onBlocksChange],
185→  );
186→
187→  const handleMoveUp = useCallback(
188→    (blockIndex: number) => {
189→      if (!onBlocksChange || blockIndex === 0) return;
190→      const updatedBlocks = [...blocksRef.current];
191→      const current = updatedBlocks[blockIndex];
192→      const above = updatedBlocks[blockIndex - 1];
193→      if (!current || !above) return;
194→      updatedBlocks[blockIndex - 1] = current;
195→      updatedBlocks[blockIndex] = above;
196→      onBlocksChange(message.id, updatedBlocks);
197→    },
198→    [message.id, onBlocksChange],
199→  );
200→
201→  const handleMoveDown = useCallback(
202→    (blockIndex: number) => {
203→      if (!onBlocksChange || blockIndex >= blocksRef.current.length - 1) return;
204→      const updatedBlocks = [...blocksRef.current];
205→      const current = updatedBlocks[blockIndex];
206→      const below = updatedBlocks[blockIndex + 1];
207→      if (!current || !below) return;
208→      updatedBlocks[blockIndex] = below;
209→      updatedBlocks[blockIndex + 1] = current;
210→      onBlocksChange(message.id, updatedBlocks);
211→    },
212→    [message.id, onBlocksChange],
213→  );
214→
215→  const handleInsertBlock = useCallback(
216→    (blockIndex: number, block: Block) => {
217→      if (!onBlocksChange) return;
218→      const updatedBlocks = [...blocksRef.current];
219→      updatedBlocks.splice(blockIndex, 0, block);
220→      onBlocksChange(message.id, updatedBlocks);
221→    },
222→    [message.id, onBlocksChange],
223→  );
224→
225→  return (
226→    <article
227→      className={cn(
228→        "rounded-[1.55rem] border border-border/80 px-4 py-5 sm:px-5",
229→        message.role === "assistant" ? "bg-card/92" : "bg-secondary/30",
230→        isDeleted && "opacity-50",
231→      )}
232→    >
233→      {isDeleted && (
234→        <div className="mb-3 flex items-center justify-between rounded-xl bg-red-50 border border-red-200/60 px-3 py-2 text-xs text-red-700">
235→          <span>Gelöscht</span>
236→          {onRestore && (
237→            <button
238→              type="button"
239→              className="text-red-600 hover:text-red-800 underline"
240→              onClick={(e) => {
241→                e.stopPropagation();
242→                onRestore();
243→              }}
244→            >
245→              Wiederherstellen
246→            </button>
247→          )}
248→        </div>
249→      )}
250→      <div className="mb-4 flex items-center gap-3 text-xs uppercase tracking-[0.18em] text-muted-foreground">
251→        <span>{getRoleLabel(message.role)}</span>
252→        <span>{messageIndex + 1}</span>
253→        {!isDeleted && (onDeleteMessage || onCopyMessage) && (
254→          <span className="ml-auto flex items-center gap-1">
255→            {onCopyMessage && (
256→              <button
257→                type="button"
258→                className="rounded-lg p-1.5 text-muted-foreground hover:bg-secondary/50 hover:text-foreground transition-colors"
259→                onClick={(e) => {
260→                  e.stopPropagation();
261→                  onCopyMessage();
262→                }}
263→                aria-label="Nachricht kopieren"
264→                data-testid={`copy-message-${message.id}`}
265→              >
266→                <ClipboardCopy className="h-4 w-4" />
267→              </button>
268→            )}
269→            {onDeleteMessage && onDeleteRound && (
270→              <MessageDeleteMenu
271→                onDeleteMessage={onDeleteMessage}
272→                onDeleteRound={onDeleteRound}
273→              />
274→            )}
275→          </span>
276→        )}
277→      </div>
278→      <div className="space-y-4">
279→        {message.blocks.map((block, blockIndex) => {
280→          const blockText = blockToPlainText(block);
281→          const blockEffects =
282→            effectsMap.get(`${message.id}:${block.id}`) ?? [];
283→          const isSelected =
284→            selectedBlock?.messageId === message.id &&
285→            selectedBlock.blockIndex === blockIndex;
286→          const isHighlighted = highlightedBlocks.has(
287→            `${message.id}:${block.id}`,
288→          );
289→          const emitSelection = (
290→            anchor: ViewportAnchor,
291→            selectedText: string,
292→          ) => {
293→            lastSelectionInteractionAt.current = Date.now();
294→
295→            onSelectBlock(
296→              {
297→                blockId: block.id,
298→                blockIndex,
299→                blockType: block.type,
300→                messageId: message.id,
301→                messageIndex,
302→                messageRole: message.role,
303→                selectedText,
304→                textQuote: truncateSelectionText(selectedText),
305→              },
306→              anchor,
307→            );
308→          };
309→
310→          const inserts = collectInserts(blockEffects);
311→
