 3→
 4→type TableBlock = Extract<Block, { type: "table" }>;
 5→
 6→export function createEmptyTable(cols: number, rows: number): TableBlock {
 7→  return {
 8→    id: generateBlockId(),
 9→    type: "table",
10→    headers: Array.from({ length: cols }, (_, i) => `Spalte ${i + 1}`),
11→    rows: Array.from({ length: rows }, () =>
12→      Array.from({ length: cols }, () => ""),
13→    ),
14→  };
15→}
16→
17→export function addRow(table: TableBlock): TableBlock {
18→  const emptyRow = Array.from({ length: table.headers.length }, () => "");
19→  return { ...table, rows: [...table.rows, emptyRow] };
20→}
21→
22→export function addColumn(table: TableBlock): TableBlock {
23→  const newHeader = `Spalte ${table.headers.length + 1}`;
24→  return {
25→    ...table,
26→    headers: [...table.headers, newHeader],
27→    rows: table.rows.map((row) => [...row, ""]),
28→  };
29→}
30→
31→export function removeRow(table: TableBlock, rowIndex: number): TableBlock {
32→  if (table.rows.length <= 1) return table;
33→  return { ...table, rows: table.rows.filter((_, i) => i !== rowIndex) };
34→}
35→
36→export function removeColumn(table: TableBlock, colIndex: number): TableBlock {
37→  if (table.headers.length <= 1) return table;
38→  return {
39→    ...table,
40→    headers: table.headers.filter((_, i) => i !== colIndex),
41→    rows: table.rows.map((row) => row.filter((_, i) => i !== colIndex)),
42→  };
43→}
