  9→function collectCustomStyles(effects: RuleEffect[]) {
 10→  const containerStyle: Record<string, string> = {};
 11→  const itemStyle: Record<string, string> = {};
 12→  const textStyle: Record<string, string> = {};
 13→  let textTransform: CustomStyleEffect["textTransform"] = null;
 14→  let headingLevel: number | undefined;
 15→
 16→  for (const effect of effects) {
 17→    if (effect.type !== "custom_style") continue;
 18→    if (effect.containerStyle)
 19→      Object.assign(containerStyle, effect.containerStyle);
 20→    if (effect.itemStyle) Object.assign(itemStyle, effect.itemStyle);
 21→    if (effect.textStyle) Object.assign(textStyle, effect.textStyle);
 22→    if (effect.textTransform) textTransform = effect.textTransform;
 23→    if (effect.headingLevel) headingLevel = effect.headingLevel;
 24→  }
 25→
 26→  return {
 27→    containerStyle:
 28→      Object.keys(containerStyle).length > 0 ? containerStyle : undefined,
 29→    itemStyle: Object.keys(itemStyle).length > 0 ? itemStyle : undefined,
 30→    textStyle: Object.keys(textStyle).length > 0 ? textStyle : undefined,
 31→    textTransform,
 32→    headingLevel,
 33→  };
 34→}
