 64→  conversation: Conversation,
 65→): Map<string, RuleEffect[]> {
 66→  const activeRules = rules.filter((r) => r.status === "active");
 67→  const effectsMap = new Map<string, RuleEffect[]>();
 68→
 69→  for (const message of conversation.messages) {
 70→    const context: ReaderMatchContext = {
 71→      messageRole: message.role,
 72→      blocks: message.blocks,
 73→    };
 74→
 75→    for (
 76→      let blockIndex = 0;
 77→      blockIndex < message.blocks.length;
 78→      blockIndex += 1
 79→    ) {
 80→      const block = message.blocks[blockIndex];
 81→
 82→      if (!block) {
 83→        continue;
 84→      }
 85→
 86→      const effects = activeRules
 87→        .filter((rule) =>
 88→          matchesReaderRule(
 89→            rule,
 90→            message.id,
 91→            blockIndex,
 92→            block.type,
 93→            blockToPlainText(block),
 94→            context,
 95→            block.id,
 96→          ),
 97→        )
 98→        .map((rule) => rule.compiledRule)
 99→        .filter((effect): effect is RuleEffect => effect !== undefined)
100→        .map(normalizeLegacyEffect);
101→
102→      if (effects.length > 0) {
103→        effectsMap.set(`${message.id}:${block.id}`, effects);
104→      }
105→    }
106→  }
107→
108→  return effectsMap;
109→}
110→
111→export function applyMarkdownRules(content: string, rules: FormatRule[]) {
112→  const lines = content.split("\n");
113→  const nextLines = [...lines];
114→
115→  for (const rule of rules) {
116→    if (rule.status !== "active") {
117→      continue;
118→    }
119→
120→    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
121→    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
122→
123→    if (!parsedSelector.success || !parsedEffect.success) {
124→      continue;
125→    }
126→
127→    const selector = parsedSelector.data;
128→    const effect = normalizeLegacyEffect(parsedEffect.data);
129→
130→    const strategy = "strategy" in selector ? selector.strategy : undefined;
131→
132→    if (strategy === "compound") {
133→      const transform = effect.markdownTransform;
134→      if (!transform) continue;
135→
136→      // Compound in Markdown: textPattern match on each line
137→      // blockType/messageRole/context not relevant for Markdown (line-based only)
138→      const textPattern =
139→        "textPattern" in selector ? selector.textPattern : null;
140→
141→      for (let index = 0; index < nextLines.length; index += 1) {
142→        const line = nextLines[index] ?? "";
143→
144→        // If textPattern set: only transform matching lines
145→        if (textPattern) {
146→          try {
147→            if (!new RegExp(textPattern).test(line)) continue;
148→          } catch {
149→            continue;
150→          }
151→        }
152→
153→        // Apply transform (same switch logic as for exact)
154→        switch (transform) {
155→          case "promote_to_heading":
156→            nextLines[index] = `## ${line.replace(/^#+\s*/, "")}`.trimEnd();
157→            break;
158→          case "bold_prefix_before_colon":
159→            nextLines[index] = line.replace(
160→              /^([^:\n]{1,120}:)(?!\*)/,
161→              "**$1**",
162→            );
163→            break;
164→          case "normalize_list_structure": {
165→            const trimmedLine = line.trim();
166→            if (!trimmedLine) break;
167→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
168→              ? trimmedLine
169→              : `- ${trimmedLine}`;
170→            break;
171→          }
172→          case "normalize_markdown_table":
173→            if (line.includes("|")) {
174→              nextLines[index] = line
175→                .split("|")
176→                .map((cell) => cell.trim())
177→                .join(" | ")
178→                .trim();
179→            }
180→            break;
181→          case "reshape_markdown_block":
182→            nextLines[index] = line.trimEnd();
183→            break;
184→        }
185→      }
186→      continue;
187→    }
188→
189→    // All effects are now custom_style after normalization
190→    {
191→      const transform = effect.markdownTransform;
192→      if (!transform) continue;
193→
194→      if (
195→        strategy === "prefix_before_colon" &&
196→        transform === "bold_prefix_before_colon"
197→      ) {
198→        for (let index = 0; index < nextLines.length; index += 1) {
199→          const line = nextLines[index] ?? "";
200→          nextLines[index] = line.replace(/^([^:\n]{1,120}:)(?!\*)/, "**$1**");
201→        }
202→        continue;
203→      }
204→
205→      if (
206→        strategy === "markdown_table" &&
207→        transform === "normalize_markdown_table"
208→      ) {
209→        for (let index = 0; index < nextLines.length; index += 1) {
210→          const line = nextLines[index] ?? "";
211→          if (!line.includes("|")) continue;
212→          nextLines[index] = line
213→            .split("|")
214→            .map((cell) => cell.trim())
215→            .join(" | ")
216→            .trim();
217→        }
218→        continue;
219→      }
220→
221→      const lineStart = "lineStart" in selector ? selector.lineStart : null;
222→      const lineEnd = "lineEnd" in selector ? selector.lineEnd : lineStart;
223→      if (!lineStart || !lineEnd) continue;
224→      const startIndex = Math.max(0, lineStart - 1);
225→      const endIndex = Math.min(nextLines.length - 1, lineEnd - 1);
226→
227→      switch (transform) {
228→        case "promote_to_heading":
229→          nextLines[startIndex] =
230→            `## ${nextLines[startIndex]?.replace(/^#+\s*/, "") ?? ""}`.trimEnd();
231→          break;
232→        case "bold_prefix_before_colon":
233→          for (let index = startIndex; index <= endIndex; index += 1) {
234→            const line = nextLines[index] ?? "";
235→            nextLines[index] = line.replace(
236→              /^([^:\n]{1,120}:)(?!\*)/,
237→              "**$1**",
238→            );
239→          }
240→          break;
241→        case "normalize_list_structure":
242→          for (let index = startIndex; index <= endIndex; index += 1) {
243→            const line = nextLines[index] ?? "";
244→            const trimmedLine = line.trim();
245→            if (!trimmedLine) continue;
246→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
247→              ? trimmedLine
248→              : `- ${trimmedLine}`;
249→          }
250→          break;
251→        case "normalize_markdown_table":
252→          for (let index = startIndex; index <= endIndex; index += 1) {
253→            const line = nextLines[index] ?? "";
254→            nextLines[index] = line
255→              .split("|")
256→              .map((cell) => cell.trim())
257→              .join(" | ")
258→              .trim();
259→          }
260→          break;
261→        case "reshape_markdown_block":
262→          for (let index = startIndex; index <= endIndex; index += 1) {
263→            nextLines[index] = (nextLines[index] ?? "").trimEnd();
264→          }
265→          break;
266→      }
267→    }
268→  }
269→
270→  return nextLines.join("\n");
271→}
