 32→// ---------------------------------------------------------------------------
 33→// Pure utility: extract text from any block type
 34→// ---------------------------------------------------------------------------
 35→
 36→export function getBlockText(block: Block): string {
 37→  switch (block.type) {
 38→    case "paragraph":
 39→    case "heading":
 40→    case "quote":
 41→    case "code":
 42→      return block.text;
 43→    case "list":
 44→      return block.items.join("\n");
 45→    case "table": {
 46→      const headerLine = block.headers.join(" | ");
 47→      const rows = block.rows.map((row) => row.join(" | ")).join("\n");
 48→      return rows ? `${headerLine}\n${rows}` : headerLine;
 49→    }
 50→  }
 51→}
 52→
 53→// ---------------------------------------------------------------------------
 54→// Pure utility: convert a block to a different type
 55→// ---------------------------------------------------------------------------
 56→
 57→export type ConvertibleBlockType = "paragraph" | "heading" | "quote" | "list";
 58→
 59→export function convertBlockType(
 60→  block: Block,
 61→  targetType: ConvertibleBlockType,
 62→): Block {
 63→  const text = getBlockText(block);
 64→  const id = block.id ?? generateBlockId();
 65→  switch (targetType) {
 66→    case "paragraph":
 67→      return { id, type: "paragraph", text };
 68→    case "heading":
 69→      return { id, type: "heading", level: 2, text };
 70→    case "quote":
 71→      return { id, type: "quote", text };
 72→    case "list":
 73→      return { id, type: "list", ordered: false, items: [text] };
 74→  }
 75→}
