// @vitest-environment jsdom
import "@testing-library/jest-dom/vitest";

import { fireEvent, render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { type Mock, beforeAll, describe, expect, test, vi } from "vitest";

import { TableEditor } from "./table-editor";

// ---------------------------------------------------------------------------
// Radix UI polyfills
// ---------------------------------------------------------------------------

beforeAll(() => {
  Element.prototype.hasPointerCapture ??= vi.fn().mockReturnValue(false);
  Element.prototype.setPointerCapture ??= vi.fn();
  Element.prototype.releasePointerCapture ??= vi.fn();
  Element.prototype.scrollIntoView ??= vi.fn();
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createTableBlock(
  overrides: {
    headers?: string[];
    rows?: string[][];
  } = {},
) {
  return {
    id: "block-1",
    type: "table" as const,
    headers: overrides.headers ?? ["Name", "Age"],
    rows: overrides.rows ?? [
      ["Alice", "30"],
      ["Bob", "25"],
    ],
  };
}

function createMaxTable() {
  return createTableBlock({
    headers: Array.from({ length: 10 }, (_, i) => `Col ${i + 1}`),
    rows: Array.from({ length: 10 }, (_, ri) =>
      Array.from({ length: 10 }, (_, ci) => `r${ri}c${ci}`),
    ),
  });
}

function createMinTable() {
  return createTableBlock({
    headers: ["Only"],
    rows: [["Cell"]],
  });
}

function renderTableEditor(
  overrides: {
    block?: ReturnType<typeof createTableBlock>;
    effects?: [];
    onBlockChange?: Mock;
  } = {},
) {
  const block = overrides.block ?? createTableBlock();
  const onBlockChange = overrides.onBlockChange ?? vi.fn();
  const effects = overrides.effects ?? [];

  const result = render(
    <TableEditor
      block={block}
      messageId="msg-1"
      blockIndex={0}
      effects={effects}
      onBlockChange={onBlockChange}
    />,
  );

  return { ...result, block, onBlockChange };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("TableEditor", () => {
  describe("cell editing", () => {
    test("editing a body cell and blurring calls onBlockChange with updated data", () => {
      const { onBlockChange, container } = renderTableEditor();

      const cells = container.querySelectorAll("[contenteditable]");
      // First 2 cells are headers, next are body cells
      const bodyCell = cells[2] as HTMLDivElement; // Alice

      bodyCell.textContent = "Charlie";
      fireEvent.blur(bodyCell);

      expect(onBlockChange).toHaveBeenCalledWith("msg-1", 0, {
        id: "block-1",
        type: "table",
        headers: ["Name", "Age"],
        rows: [
          ["Charlie", "30"],
          ["Bob", "25"],
        ],
      });
    });

    test("editing a header cell and blurring calls onBlockChange with updated headers", () => {
      const { onBlockChange, container } = renderTableEditor();

      const cells = container.querySelectorAll("[contenteditable]");
      const headerCell = cells[0] as HTMLDivElement; // Name

      headerCell.textContent = "Full Name";
      fireEvent.blur(headerCell);

      expect(onBlockChange).toHaveBeenCalledWith("msg-1", 0, {
        id: "block-1",
        type: "table",
        headers: ["Full Name", "Age"],
        rows: [
          ["Alice", "30"],
          ["Bob", "25"],
        ],
      });
    });

    test("blurring a cell without changes does not call onBlockChange", () => {
      const { onBlockChange, container } = renderTableEditor();

      const cells = container.querySelectorAll("[contenteditable]");
      const headerCell = cells[0] as HTMLDivElement;

      fireEvent.blur(headerCell);

      expect(onBlockChange).not.toHaveBeenCalled();
    });
  });

  describe("add row", () => {
    test("clicking add row button calls onBlockChange with an additional row", async () => {
      const user = userEvent.setup();
      const { onBlockChange } = renderTableEditor();

      const addRowBtn = screen.getByRole("button", {
        name: /zeile hinzufügen/i,
      });
      await user.click(addRowBtn);

      expect(onBlockChange).toHaveBeenCalledWith("msg-1", 0, {
        id: "block-1",
        type: "table",
        headers: ["Name", "Age"],
        rows: [
          ["Alice", "30"],
          ["Bob", "25"],
          ["", ""],
        ],
      });
    });
  });

  describe("add column", () => {
    test("clicking add column button calls onBlockChange with an additional column", async () => {
      const user = userEvent.setup();
      const { onBlockChange } = renderTableEditor();

      const addColBtn = screen.getByRole("button", {
        name: /spalte hinzufügen/i,
      });
      await user.click(addColBtn);

      expect(onBlockChange).toHaveBeenCalledWith("msg-1", 0, {
        id: "block-1",
        type: "table",
        headers: ["Name", "Age", "Spalte 3"],
        rows: [
          ["Alice", "30", ""],
          ["Bob", "25", ""],
        ],
      });
    });
  });

  describe("remove column", () => {
    test("clicking remove column button calls onBlockChange without that column", async () => {
      const user = userEvent.setup();
      const { onBlockChange } = renderTableEditor();

      const removeColBtns = screen.getAllByRole("button", {
        name: /spalte entfernen/i,
      });
      // Remove first column ("Name")
      await user.click(removeColBtns[0]);

      expect(onBlockChange).toHaveBeenCalledWith("msg-1", 0, {
        id: "block-1",
        type: "table",
        headers: ["Age"],
        rows: [["30"], ["25"]],
      });
    });
  });

  describe("remove row", () => {
    test("clicking remove row button calls onBlockChange without that row", async () => {
      const user = userEvent.setup();
      const { onBlockChange } = renderTableEditor();

      const removeRowBtns = screen.getAllByRole("button", {
        name: /zeile entfernen/i,
      });
      // Remove first row
      await user.click(removeRowBtns[0]);

      expect(onBlockChange).toHaveBeenCalledWith("msg-1", 0, {
        id: "block-1",
        type: "table",
        headers: ["Name", "Age"],
        rows: [["Bob", "25"]],
      });
    });
  });

  describe("limits", () => {
    test("add row button is not rendered when table has 10 rows", () => {
      renderTableEditor({ block: createMaxTable() });

      expect(
        screen.queryByRole("button", { name: /zeile hinzufügen/i }),
      ).not.toBeInTheDocument();
    });

    test("add column button is not rendered when table has 10 columns", () => {
      renderTableEditor({ block: createMaxTable() });

      expect(
        screen.queryByRole("button", { name: /spalte hinzufügen/i }),
      ).not.toBeInTheDocument();
    });

    test("remove row buttons are not rendered when table has 1 row", () => {
      renderTableEditor({ block: createMinTable() });

      expect(
        screen.queryByRole("button", { name: /zeile entfernen/i }),
      ).toBeNull();
    });

    test("remove column buttons are not rendered when table has 1 column", () => {
      renderTableEditor({ block: createMinTable() });

      expect(
        screen.queryByRole("button", { name: /spalte entfernen/i }),
      ).toBeNull();
    });
  });

  describe("tab navigation", () => {
    test("Tab moves focus to the next editable cell", () => {
      const { container } = renderTableEditor();

      const cells = container.querySelectorAll(
        "[contenteditable]",
      ) as NodeListOf<HTMLDivElement>;

      cells[0].focus();
      expect(document.activeElement).toBe(cells[0]);

      fireEvent.keyDown(cells[0], { key: "Tab" });

      expect(document.activeElement).toBe(cells[1]);
    });

    test("Shift+Tab moves focus to the previous editable cell", () => {
      const { container } = renderTableEditor();

      const cells = container.querySelectorAll(
        "[contenteditable]",
      ) as NodeListOf<HTMLDivElement>;

      cells[1].focus();
      expect(document.activeElement).toBe(cells[1]);

      fireEvent.keyDown(cells[1], { key: "Tab", shiftKey: true });

      expect(document.activeElement).toBe(cells[0]);
    });
  });
});

import type { Block, RuleEffect } from "@chat-exporter/shared";
import { useCallback, useEffect, useRef } from "react";

import { getReaderBlockStyle } from "@/components/format-workspace/rule-engine";

import {
  addColumn,
  addRow,
  canAddColumn,
  canAddRow,
  canRemoveColumn,
  canRemoveRow,
  removeColumn,
  removeRow,
} from "./table-utils";

type TableBlock = Extract<Block, { type: "table" }>;

interface TableEditorProps {
  block: TableBlock;
  messageId: string;
  blockIndex: number;
  effects: RuleEffect[];
  onBlockChange: (messageId: string, blockIndex: number, block: Block) => void;
}

// ---------------------------------------------------------------------------
// EditableCell — uncontrolled contentEditable div
// ---------------------------------------------------------------------------

function EditableCell({
  value,
  onCommit,
}: { value: string; onCommit: (v: string) => void }) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (ref.current && ref.current.textContent !== value) {
      ref.current.textContent = value;
    }
  }, [value]);

  return (
    <div
      ref={ref}
      contentEditable
      suppressContentEditableWarning
      onBlur={() => {
        const text = ref.current?.textContent ?? "";
        if (text !== value) onCommit(text);
      }}
      onKeyDown={(e) => {
        if (e.key === "Enter") {
          e.preventDefault();
          ref.current?.blur();
        }
      }}
      className="min-w-[2rem] px-1 outline-none"
    />
  );
}

// ---------------------------------------------------------------------------
// TableEditor
// ---------------------------------------------------------------------------

export function TableEditor({
  block,
  messageId,
  blockIndex,
  effects,
  onBlockChange,
}: TableEditorProps) {
  const tableRef = useRef<HTMLDivElement>(null);

  const handleHeaderChange = useCallback(
    (colIndex: number, value: string) => {
      const newHeaders = [...block.headers];
      newHeaders[colIndex] = value;
      onBlockChange(messageId, blockIndex, { ...block, headers: newHeaders });
    },
    [block, messageId, blockIndex, onBlockChange],
  );

  const handleCellChange = useCallback(
    (rowIndex: number, colIndex: number, value: string) => {
      const newRows = block.rows.map((row, ri) =>
        ri === rowIndex
          ? row.map((cell, ci) => (ci === colIndex ? value : cell))
          : row,
      );
      onBlockChange(messageId, blockIndex, { ...block, rows: newRows });
    },
    [block, messageId, blockIndex, onBlockChange],
  );

  const handleAddRow = useCallback(
    () => onBlockChange(messageId, blockIndex, addRow(block)),
    [block, messageId, blockIndex, onBlockChange],
  );

  const handleAddColumn = useCallback(
    () => onBlockChange(messageId, blockIndex, addColumn(block)),
    [block, messageId, blockIndex, onBlockChange],
  );

  const handleRemoveRow = useCallback(
    (rowIndex: number) =>
      onBlockChange(messageId, blockIndex, removeRow(block, rowIndex)),
    [block, messageId, blockIndex, onBlockChange],
  );

  const handleRemoveColumn = useCallback(
    (colIndex: number) =>
      onBlockChange(messageId, blockIndex, removeColumn(block, colIndex)),
    [block, messageId, blockIndex, onBlockChange],
  );

  // Tab navigation across all editable cells in the table
  const handleTableKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>) => {
      if (e.key !== "Tab") return;
      if (!tableRef.current) return;

      const cells = tableRef.current.querySelectorAll("[contenteditable]");
      if (cells.length === 0) return;

      const currentIndex = Array.from(cells).indexOf(
        document.activeElement as Element,
      );
      if (currentIndex === -1) return;

      e.preventDefault();

      const nextIndex = e.shiftKey ? currentIndex - 1 : currentIndex + 1;
      if (nextIndex >= 0 && nextIndex < cells.length) {
        (cells[nextIndex] as HTMLElement).focus();
      }
    },
    [],
  );

  const containerStyle = getReaderBlockStyle(effects);
  const showRemoveCol = canRemoveColumn(block);
  const showRemoveRow = canRemoveRow(block);
  const showAddCol = canAddColumn(block);
  const showAddRow = canAddRow(block);

  return (
    <div
      ref={tableRef}
      style={containerStyle}
      className="overflow-x-auto rounded-2xl border border-border/80"
      onKeyDown={handleTableKeyDown}
    >
      <table className="min-w-full table-fixed text-left text-sm">
        <thead className="bg-secondary/70 text-secondary-foreground">
          <tr>
            {block.headers.map((header, colIndex) => (
              <th
                key={`h-${colIndex}`}
                className="group relative px-4 py-3 font-medium"
              >
                <EditableCell
                  value={header}
                  onCommit={(v) => handleHeaderChange(colIndex, v)}
                />
                {showRemoveCol && (
                  <button
                    type="button"
                    className="absolute -top-2 right-1 hidden rounded-full bg-destructive/80 px-1.5 text-xs text-destructive-foreground group-hover:block"
                    onClick={() => handleRemoveColumn(colIndex)}
                    aria-label="Spalte entfernen"
                  >
                    &times;
                  </button>
                )}
              </th>
            ))}
            {showAddCol && (
              <th className="w-8">
                <button
                  type="button"
                  className="flex h-full w-full items-center justify-center text-muted-foreground hover:text-foreground"
                  onClick={handleAddColumn}
                  aria-label="Spalte hinzufügen"
                >
                  +
                </button>
              </th>
            )}
          </tr>
        </thead>
        <tbody>
          {block.rows.map((row, rowIndex) => (
            <tr
              key={`r-${rowIndex}`}
              className="group border-t border-border/80"
            >
              {row.map((cell, colIndex) => (
                <td
                  key={`c-${rowIndex}-${colIndex}`}
                  className="px-4 py-3 align-top text-muted-foreground"
                >
                  <EditableCell
                    value={cell}
                    onCommit={(v) => handleCellChange(rowIndex, colIndex, v)}
                  />
                </td>
              ))}
              {showRemoveRow && (
                <td className="px-1 py-3">
                  <button
                    type="button"
                    className="hidden rounded-full bg-destructive/80 px-1.5 text-xs text-destructive-foreground group-hover:block"
                    onClick={() => handleRemoveRow(rowIndex)}
                    aria-label="Zeile entfernen"
                  >
                    &times;
                  </button>
                </td>
              )}
            </tr>
          ))}
        </tbody>
      </table>
      {showAddRow && (
        <button
          type="button"
          className="w-full border-t border-dashed border-border/80 py-2 text-center text-sm text-muted-foreground hover:bg-secondary/30 hover:text-foreground"
          onClick={handleAddRow}
          aria-label="Zeile hinzufügen"
        >
          + Zeile
        </button>
      )}
    </div>
  );
}

