 31→function EditableCell({
 32→  value,
 33→  onCommit,
 34→}: {
 35→  value: string;
 36→  onCommit: (v: string) => void;
 37→}) {
 38→  const ref = useRef<HTMLDivElement>(null);
 39→
 40→  useEffect(() => {
 41→    if (ref.current && ref.current.textContent !== value) {
 42→      ref.current.textContent = value;
 43→    }
 44→  }, [value]);
 45→
 46→  return (
 47→    <div
 48→      ref={ref}
 49→      role="textbox"
 50→      contentEditable
 51→      suppressContentEditableWarning
 52→      onBlur={() => {
 53→        const text = ref.current?.textContent ?? "";
 54→        if (text !== value) onCommit(text);
 55→      }}
 56→      onKeyDown={(e) => {
 57→        if (e.key === "Enter") {
 58→          e.preventDefault();
 59→          ref.current?.blur();
 60→        }
 61→      }}
 62→      className="min-w-[2rem] px-1 outline-none"
 63→    />
 64→  );
 65→}
